+/// Fold (icmp ult (add A, B), A) | (icmp ult (add A, B), B) into
+/// (icmp ult (add A, B), A).
+/// Also fold (icmp uge (add A, B), A) & (icmp uge (add A, B), B) into
+/// (icmp uge (add A, B), A).
+/// For unsigned addition, overflow occurs iff (A + B) < A, which is equivalent
+/// to (A + B) < B. Therefore, OR of both overflow conditions is equivalent to
+/// either, and AND of both non-overflow conditions is equivalent to either.
+static Value *foldUnsignedAddOverflowCheck(ICmpInst *LHS, ICmpInst *RHS,
+                                           bool IsAnd,
+                                           InstCombiner::BuilderTy &Builder) {
+  ICmpInst::Predicate PredL = LHS->getPredicate();
+  ICmpInst::Predicate PredR = RHS->getPredicate();
+
+  Value *LHS0 = LHS->getOperand(0);
+  Value *LHS1 = LHS->getOperand(1);
+  Value *RHS0 = RHS->getOperand(0);
+  Value *RHS1 = RHS->getOperand(1);
+
+  // Both ICmp must compare the same value (the add result).
+  if (LHS0 != RHS0)
+    return nullptr;
+
+  // The compared value must be an add.
+  Value *A, *B;
+  if (!match(LHS0, m_Add(m_Value(A), m_Value(B))))
+    return nullptr;
+
+  // Helper to check if a predicate is an overflow check (ult/ugt with sum < operand).
+  // Overflow: sum < a  OR  sum < b  OR  a > sum  OR  b > sum
+  auto IsOverflowPred = [&](ICmpInst::Predicate Pred, Value *Op0, Value *Op1,
+                            Value *AddOp) -> bool {
+    // sum < add_op
+    if (Pred == ICmpInst::ICMP_ULT && Op0 == LHS0 && Op1 == AddOp)
+      return true;
+    // add_op > sum
+    if (Pred == ICmpInst::ICMP_UGT && Op0 == AddOp && Op1 == LHS0)
+      return true;
+    return false;
+  };
+
+  // Helper to check if a predicate is a non-overflow check (uge/ule with sum >= operand).
+  // Non-overflow: sum >= a  OR  sum >= b  OR  a <= sum  OR  b <= sum
+  auto IsNonOverflowPred = [&](ICmpInst::Predicate Pred, Value *Op0, Value *Op1,
+                               Value *AddOp) -> bool {
+    // sum >= add_op
+    if (Pred == ICmpInst::ICMP_UGE && Op0 == LHS0 && Op1 == AddOp)
+      return true;
+    // add_op <= sum
+    if (Pred == ICmpInst::ICMP_ULE && Op0 == AddOp && Op1 == LHS0)
+      return true;
+    return false;
+  };
+
+  // Check for OR of overflow checks: (sum < a) | (sum < b) or variants
+  if (!IsAnd) {
+    bool LIsOverflowA = IsOverflowPred(PredL, LHS0, LHS1, A);
+    bool LIsOverflowB = IsOverflowPred(PredL, LHS0, LHS1, B);
+    bool RIsOverflowA = IsOverflowPred(PredR, RHS0, RHS1, A);
+    bool RIsOverflowB = IsOverflowPred(PredR, RHS0, RHS1, B);
+
+    // One checks overflow against A, the other against B
+    if ((LIsOverflowA && RIsOverflowB) || (LIsOverflowB && RIsOverflowA))
+      return LHS;
+  }
+
+  // Check for AND of non-overflow checks: (sum >= a) & (sum >= b) or variants
+  if (IsAnd) {
+    bool LIsNonOverflowA = IsNonOverflowPred(PredL, LHS0, LHS1, A);
+    bool LIsNonOverflowB = IsNonOverflowPred(PredL, LHS0, LHS1, B);
+    bool RIsNonOverflowA = IsNonOverflowPred(PredR, RHS0, RHS1, A);
+    bool RIsNonOverflowB = IsNonOverflowPred(PredR, RHS0, RHS1, B);
+
+    // One checks non-overflow against A, the other against B
+    if ((LIsNonOverflowA && RIsNonOverflowB) || (LIsNonOverflowB && RIsNonOverflowA))
+      return LHS;
+  }
+
+  return nullptr;
+}
